#include <stdio.h>
#include <string.h>
int main() {
    char s[200001];
    scanf("%s", s);
    int n = strlen(s);
    int interesting = 0, boring = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            char substr[j - i];
            strncpy(substr, s + i, j - i);
            substr[j - i] = '\0';
            int len = strlen(substr);
            if (len % 3 == 0) {
                char tandem[3 * len];
                strcpy(tandem, substr);
                strcat(tandem, substr);
                strcat(tandem, substr);
                if (strncmp(s + i, tandem, 3 * len) == 0) {
                    if (i + 3 * len >= n || s[i + 3 * len] != substr[0]) {
                        interesting++;
                    } else {
                        boring++;
                    }
                }
            }
        }
    }
    printf("%d %d\n", interesting, boring);
    return 0;
}

