                    String tandem = substr + substr + substr;
                    if (s.substring(i, i + 3 * len).equals(tandem)) {
                        if (i + 3 * len >= n || s.charAt(i + 3 * len) != substr.charAt(0)) {
                            interesting++;
                        } else {
                            boring++;
                        }
                    }
                }
            }
        }
        System.out.println(interesting + " " + boring);
